<script setup lang="ts">
import { Head, Link } from '@inertiajs/vue3';
import { ArrowLeft, BarChart3, BriefcaseBusiness, Check, ChevronRight, CircleCheck, Clock3, CreditCard, Eye, Heart, Megaphone, MousePointerClick, Play, Plus, Sparkles, Users, X } from '@lucide/vue';
import { computed, onMounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';
const videos=ref<any[]>([]),campaigns=ref<any[]>([]),sports=ref<any[]>([]),selected=ref<any>(),previewing=ref<any>(),loading=ref(true),view=ref('dashboard'),step=ref(1),type=ref('post_promotion'),goal=ref('views'),budget=ref(100),days=ref(3),title=ref(''),description=ref(''),destination=ref(''),sportId=ref(''),gender=ref('all'),province=ref(''),minAge=ref(13),maxAge=ref(65),notice=ref(''),error=ref(''),saving=ref(false),boostSettings=ref({enabled:true,cpm_cents:5000,minimum_daily_budget_cents:5000,maximum_daily_budget_cents:1000000,maximum_duration_days:90,require_review:true,sandbox:false});
const goals=[{id:'views',label:'More video views',hint:'Reach people likely to watch',icon:Eye},{id:'followers',label:'More followers',hint:'Grow your sports audience',icon:Users},{id:'website',label:'Website visits',hint:'Drive traffic to a destination',icon:MousePointerClick},{id:'applications',label:'Sponsorship applications',hint:'Find athletes and partners',icon:BriefcaseBusiness},{id:'awareness',label:'Brand awareness',hint:'Build recognition in sport',icon:Megaphone}];
const total=computed(()=>budget.value*days.value),reach=computed(()=>{const impressions=total.value*100000/boostSettings.value.cpm_cents;return[Math.floor(impressions*.65),Math.floor(impressions*.9)]}),money=(value:number)=>new Intl.NumberFormat('en-ZA',{style:'currency',currency:'ZAR',maximumFractionDigits:0}).format(value);const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';const status=(value:string)=>value.replaceAll('_',' ').replace(/\b\w/g,c=>c.toUpperCase());
const api=async(url:string,options:RequestInit={})=>{const response=await fetch(url,{...options,credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()}});const payload=await response.json();if(!response.ok){const validation=Object.values(payload.errors??{}).flat().join(' ');throw new Error(validation||payload.message||'Unable to complete this request.')}return payload.data??payload};
const start=(campaignType:string)=>{type.value=campaignType;selected.value=undefined;title.value='';description.value='';goal.value=campaignType==='post_promotion'?'views':'applications';step.value=campaignType==='post_promotion'?1:2;view.value='create';notice.value='';error.value=''};
const choose=(video:any)=>{selected.value=video;previewing.value=undefined;title.value=video.caption||'Promoted SportsUniverse post';step.value=2};
const imageFor=(video:any)=>video.images?.find((image:any)=>image.is_cover)?.url||video.images?.[0]?.url||video.images?.find((image:any)=>image.is_cover)?.download_url||video.images?.[0]?.download_url;
const openCheckout=(checkout:any)=>{const form=document.createElement('form');form.method=checkout.method||'POST';form.action=checkout.action;Object.entries(checkout.fields??{}).forEach(([name,value])=>{const input=document.createElement('input');input.type='hidden';input.name=name;input.value=String(value??'');form.appendChild(input)});document.body.appendChild(form);form.submit()};
const submit=async(draft=false)=>{saving.value=true;error.value='';notice.value='';try{const starts=new Date(),ends=new Date();ends.setDate(ends.getDate()+days.value-1);const campaign=await api('/api/v1/campaigns',{method:'POST',body:JSON.stringify({campaign_type:type.value,video_id:selected.value?.id,title:title.value,description:description.value||null,goal:goal.value,audience:{sport_id:+sportId.value||null,gender:gender.value,province:province.value||null,min_age:minAge.value,max_age:maxAge.value},destination_url:destination.value||null,daily_budget_cents:budget.value*100,starts_on:starts.toISOString().slice(0,10),ends_on:ends.toISOString().slice(0,10),submit:!draft})});campaigns.value.unshift(campaign);if(campaign.checkout){openCheckout(campaign.checkout);return}notice.value='Campaign draft saved.';view.value='dashboard'}catch(exception:any){error.value=exception.message}finally{saving.value=false}};
const pay=async(campaign:any)=>{saving.value=true;error.value='';try{openCheckout(await api(`/api/v1/campaigns/${campaign.id}/payfast/checkout`,{method:'POST',body:'{}'}))}catch(exception:any){error.value=exception.message}finally{saving.value=false}};
const confirmSandbox=async(campaign:any)=>{saving.value=true;error.value='';try{const result=await api(`/api/v1/campaigns/${campaign.id}/payfast/sandbox-confirm`,{method:'POST',body:'{}'});campaign.status=result.status;campaign.payment_status=result.payment_status;notice.value='Test payment confirmed — your campaign is now ready for review.'}catch(exception:any){error.value=exception.message}finally{saving.value=false}};
const cancel=async(campaign:any)=>{if(!confirm('Cancel this campaign?'))return;const updated=await api(`/api/v1/campaigns/${campaign.id}/cancel`,{method:'POST',body:'{}'});Object.assign(campaign,updated)};
onMounted(async()=>{const params=new URLSearchParams(location.search),payment=params.get('payment'),campaignId=params.get('campaign'),videoId=params.get('video'),create=params.get('create');if(payment==='processing')notice.value='Payment received — adding the finishing touches to your campaign.';if(payment==='cancelled')error.value='PayFast payment was cancelled. Your campaign is safe and you can try again.';try{const [videoData,campaignData,sportData,settingsData]=await Promise.all([api('/api/v1/videos/mine'),api('/api/v1/campaigns'),api('/api/v1/sports'),api('/api/v1/campaign-settings')]);videos.value=videoData;campaigns.value=campaignData;sports.value=sportData;boostSettings.value=settingsData;budget.value=Math.max(1,settingsData.minimum_daily_budget_cents/100);const returnedCampaign=campaigns.value.find(item=>item.id===campaignId);if(payment==='processing'&&settingsData.sandbox&&returnedCampaign?.payment_status==='pending')await confirmSandbox(returnedCampaign);if(videoId){const video=videos.value.find(item=>String(item.id)===videoId);if(video){start('post_promotion');choose(video)}else{error.value='That post is not available to promote.'}}else if(create==='post'){start('post_promotion')}}finally{loading.value=false}});
</script>
<template><Head title="Advertising & Sponsorship"/><AppShell><main class="promote-page"><header class="promote-head"><button v-if="view==='create'" @click="view='dashboard'"><ArrowLeft/></button><Link v-else href="/feed"><ArrowLeft/></Link><div><h1>Advertising & sponsorship</h1><p>Create campaigns and measure how they perform.</p></div><span v-if="view==='create'">Step {{step}} of 4</span><button v-else class="new-campaign" @click="start('post_promotion')"><Plus/>New campaign</button></header><p v-if="notice" class="promote-notice">{{notice}}</p><p v-if="error" class="edit-message error">{{error}}</p>
<template v-if="view==='dashboard'"><section class="campaign-summary"><article><Megaphone/><div><strong>{{campaigns.length}}</strong><span>Total campaigns</span></div></article><article><Eye/><div><strong>{{campaigns.reduce((sum,item)=>sum+item.metrics.impressions,0).toLocaleString()}}</strong><span>Impressions</span></div></article><article><MousePointerClick/><div><strong>{{campaigns.reduce((sum,item)=>sum+item.metrics.clicks,0).toLocaleString()}}</strong><span>Clicks</span></div></article></section><section class="campaign-create-types"><button @click="start('post_promotion')"><Play/><div><strong>Promote a post</strong><span>Grow views, followers, or website visits.</span></div><ChevronRight/></button><button @click="start('sponsorship')"><BriefcaseBusiness/><div><strong>Create sponsorship campaign</strong><span>Find athletes, partners, and applicants.</span></div><ChevronRight/></button></section><section class="campaign-list"><header><div><span><Heart/> YOUR CAMPAIGNS</span><h2>Made to help you shine</h2></div><small>Track every boost in one lovely little place.</small></header><article v-for="campaign in campaigns" :key="campaign.id" :class="`campaign-card-${campaign.status}`"><div class="campaign-identity"><span>{{campaign.campaign_type.replaceAll('_',' ')}}</span><strong>{{campaign.title}}</strong><small>{{campaign.starts_on}} — {{campaign.ends_on}}</small></div><i :class="`campaign-${campaign.status}`"><CircleCheck v-if="['active','pending_review'].includes(campaign.status)"/><Clock3 v-else/>{{status(campaign.status)}}</i><dl><div><dt>Budget</dt><dd>{{money(campaign.total_budget_cents/100)}}</dd></div><div><dt>Impressions</dt><dd>{{campaign.metrics.impressions.toLocaleString()}}</dd></div><div><dt>Clicks</dt><dd>{{campaign.metrics.clicks.toLocaleString()}}</dd></div><div><dt>CTR</dt><dd>{{campaign.metrics.click_rate}}%</dd></div></dl><p v-if="campaign.status==='pending_review'" class="campaign-happy-note"><Sparkles/> Payment confirmed. Your campaign is queued for a quick review.</p><p v-else-if="campaign.review_notes">{{campaign.review_notes}}</p><div v-if="!['cancelled','completed'].includes(campaign.status)" class="campaign-actions"><button v-if="boostSettings.sandbox&&campaign.payment_status==='pending'" class="confirm-test-payment" :disabled="saving" @click="confirmSandbox(campaign)"><CircleCheck/>I completed the test payment</button><button v-else-if="['awaiting_payment','payment_failed','payment_cancelled'].includes(campaign.status)" class="pay-campaign" :disabled="saving" @click="pay(campaign)"><CreditCard/>Pay securely with PayFast</button><button class="cancel-campaign" @click="cancel(campaign)">Cancel campaign</button></div></article><div v-if="!campaigns.length&&!loading" class="promote-empty"><BarChart3/><h3>No campaigns yet</h3><p>Create a post promotion or sponsorship campaign to get started.</p></div></section></template>
<template v-else><div class="promote-progress"><i v-for="n in 4" :class="{on:n<=step}"/></div><section v-if="step===1" class="promote-card"><h2>Choose a post</h2><p>Preview a published post before choosing it for promotion.</p><div v-if="loading" class="promote-empty">Loading your posts…</div><div v-else-if="videos.length" class="promote-videos"><button v-for="video in videos" @click="previewing=video"><div><video v-if="video.media" :src="video.media.download_url" muted preload="metadata"/><img v-else-if="imageFor(video)" :src="imageFor(video)" :alt="video.caption||'Post preview'"/><span v-else class="promote-media-placeholder"><Play/></span><Play v-if="video.media"/></div><strong>{{video.caption||'SportsUniverse post'}}</strong><small>{{video.counts.views}} views · Preview</small></button></div><div v-else class="promote-empty"><h3>No published posts</h3><Link href="/upload">Create a post</Link></div></section><section v-else-if="step===2" class="promote-card"><h2>{{type==='sponsorship'?'Sponsorship details':'Campaign goal'}}</h2><label class="campaign-field">Campaign title<input v-model="title" required maxlength="180" placeholder="Name your campaign"/></label><label v-if="type==='sponsorship'" class="campaign-field">Campaign description<textarea v-model="description" maxlength="3000" placeholder="Describe the partnership, support, or applicants you are looking for."/></label><div class="promote-options"><button v-for="item in goals.filter(item=>type==='post_promotion'?['views','followers','website','awareness'].includes(item.id):['applications','website','awareness'].includes(item.id))" :class="{selected:goal===item.id}" @click="goal=item.id"><component :is="item.icon"/><span><strong>{{item.label}}</strong><small>{{item.hint}}</small></span><i><Check/></i></button></div><label v-if="['website','applications'].includes(goal)" class="campaign-field">Destination URL<input v-model="destination" type="url" placeholder="https://"/></label><footer><button @click="type==='post_promotion'?step=1:view='dashboard'">Back</button><button class="primary" :disabled="!title" @click="step=3">Target audience<ChevronRight/></button></footer></section><section v-else-if="step===3" class="promote-card"><h2>Audience and budget</h2><div class="campaign-targeting"><label>Sport<select v-model="sportId"><option value="">All sports</option><option v-for="sport in sports" :value="sport.id">{{sport.name}}</option></select></label><label>Gender<select v-model="gender"><option value="all">All</option><option value="female">Women</option><option value="male">Men</option></select></label><label>Province<input v-model="province" placeholder="All provinces"/></label><label>Minimum age<input v-model.number="minAge" type="number" min="13" max="100"/></label><label>Maximum age<input v-model.number="maxAge" type="number" min="13" max="100"/></label></div><label class="promote-range"><span>Daily budget <strong>{{money(budget)}}</strong></span><input v-model.number="budget" type="range" min="50" max="1000" step="50"/></label><label class="promote-days"><span>Duration</span><select v-model.number="days"><option v-for="n in [1,2,3,5,7,14,30]" :value="n">{{n}} day{{n>1?'s':''}}</option></select></label><div class="promote-estimate"><Sparkles/><div><small>Estimated reach</small><strong>{{reach[0].toLocaleString()}} – {{reach[1].toLocaleString()}}</strong><span>people over {{days}} days</span></div></div><footer><button @click="step=2">Back</button><button class="primary" @click="step=4">Review<ChevronRight/></button></footer></section><section v-else class="promote-card promote-review"><h2>Review campaign</h2><div v-if="selected" class="review-post"><video v-if="selected.media" :src="selected.media.download_url" muted/><img v-else-if="imageFor(selected)" :src="imageFor(selected)" :alt="selected.caption||'Selected post'"/><div><strong>{{title}}</strong><small>{{goals.find(item=>item.id===goal)?.label}}</small></div></div><div v-else class="sponsor-review"><BriefcaseBusiness/><div><strong>{{title}}</strong><p>{{description}}</p></div></div><dl><div><dt>Audience</dt><dd>{{[sports.find(item=>String(item.id)===String(sportId))?.name,gender==='all'?'All genders':gender,province].filter(Boolean).join(' · ')}}</dd></div><div><dt>Budget</dt><dd>{{money(budget)}} × {{days}} days</dd></div><div><dt>Estimated reach</dt><dd>{{reach[0].toLocaleString()}} – {{reach[1].toLocaleString()}}</dd></div><div class="total"><dt>Total</dt><dd>{{money(total)}}</dd></div></dl><footer><button :disabled="saving" @click="submit(true)">Save draft</button><button class="primary" :disabled="saving" @click="submit(false)">{{saving?'Opening PayFast…':'Continue to PayFast'}}</button></footer></section></template></main><div v-if="previewing" class="promote-preview-overlay" @click.self="previewing=undefined"><section class="promote-preview-dialog"><header><div><h2>Post preview</h2><p>Confirm this is the post you want to promote.</p></div><button aria-label="Close preview" @click="previewing=undefined"><X/></button></header><div class="promote-preview-media"><video v-if="previewing.media" :src="previewing.media.download_url" controls autoplay playsinline/><img v-else-if="imageFor(previewing)" :src="imageFor(previewing)" :alt="previewing.caption||'Post preview'"/></div><div class="promote-preview-copy"><strong>{{previewing.caption||'SportsUniverse post'}}</strong><span>{{Number(previewing.counts?.views||0).toLocaleString()}} views<span v-if="previewing.sport?.name"> · {{previewing.sport.name}}</span></span></div><footer><button @click="previewing=undefined">Keep browsing</button><button class="primary" @click="choose(previewing)">Promote this post</button></footer></section></div></AppShell></template>
